#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char S[1000005];
        scanf("%s", S);
        long long x1,y1; scanf("%lld %lld", &x1, &y1);
        long long cntR=0,cntL=0,cntU=0,cntD=0;
        for(char *p=S; *p; ++p){
            if(*p=='R') cntR++;
            else if(*p=='L') cntL++;
            else if(*p=='U') cntU++;
            else if(*p=='D') cntD++;
        }
        int Q; scanf("%d", &Q);
        while(Q--){
            long long x2,y2; scanf("%lld %lld", &x2, &y2);
            long long dx = x2 - x1;
            long long dy = y2 - y1;
            long long needR = dx>0?dx:0;
            long long needL = dx<0?-dx:0;
            long long needU = dy>0?dy:0;
            long long needD = dy<0?-dy:0;
            if(cntR>=needR && cntL>=needL && cntU>=needU && cntD>=needD){
                printf("YES %lld\n", needR+needL+needU+needD);
            }else{
                printf("NO\n");
            }
        }
    }
    return 0;
}

