import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            String S = fs.next();
            long x1 = fs.nextLong();
            long y1 = fs.nextLong();
            long cntR = 0, cntL = 0, cntU = 0, cntD = 0;
            for (int i = 0; i < S.length(); i++) {
                char c = S.charAt(i);
                switch (c) {
                    case 'R': cntR++; break;
                    case 'L': cntL++; break;
                    case 'U': cntU++; break;
                    case 'D': cntD++; break;
                }
            }
            int Q = fs.nextInt();
            while (Q-- > 0) {
                long x2 = fs.nextLong();
                long y2 = fs.nextLong();
                long dx = x2 - x1;
                long dy = y2 - y1;
                long needR = Math.max(dx, 0);
                long needL = Math.max(-dx, 0);
                long needU = Math.max(dy, 0);
                long needD = Math.max(-dy, 0);
                if (cntR >= needR && cntL >= needL && cntU >= needU && cntD >= needD) {
                    out.append("YES ").append(needR + needL + needU + needD).append('\n');
                } else {
                    out.append("NO\n");
                }
            }
        }
        System.out.print(out.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        private boolean isSpace(int c) { return c <= ' '; }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && isSpace(c));
            while (c != -1 && !isSpace(c)) {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return (int) nextLong(); }
        long nextLong() throws IOException {
            int c;
            while ((c = readByte()) != -1 && isSpace(c));
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c != -1 && !isSpace(c)) {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }
}

